// Inject visual placeholder blocks into the article HTML
const article = $('Read Article').first().json;
let html = article.draft_html || '';
const visuals = article.visual_suggestions || [];

// Style for placeholder blocks
const placeholderStyle = 'background: #f0f4ff; border: 2px dashed #80B3FF; border-radius: 8px; padding: 24px; margin: 24px 0; text-align: center; color: #060850; font-size: 14px;';

// Process each visual suggestion
for (const visual of visuals) {
  const placeholder = `<div style="${placeholderStyle}"><p style="font-weight: 600; margin-bottom: 8px;">[${visual.type === 'cover' ? 'COVER IMAGE' : 'VISUAL'}]</p><p>${visual.description}</p></div>`;

  if (visual.type === 'cover') {
    // Insert cover placeholder at the very top
    html = placeholder + '\n' + html;
  } else if (visual.placement) {
    // Try to insert after the section heading that matches the placement
    const placementLower = visual.placement.toLowerCase();

    // Look for h2 or h3 headings that contain the placement text
    const headingRegex = new RegExp(
      `(<h[23][^>]*>.*?${placementLower.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}.*?</h[23]>)`,
      'i'
    );

    if (headingRegex.test(html)) {
      html = html.replace(headingRegex, `$1\n${placeholder}`);
    } else {
      // If no matching heading found, append before the last section
      html = html + '\n' + placeholder;
    }
  }
}

return [{
  json: {
    article_id: article.id,
    title: article.title || 'Untitled',
    slug: article.slug || 'untitled',
    final_html: html,
    meta_description: article.meta_description || ''
  }
}];

